+        let h = LinkHeader::new().paginate("/users", 3, 10, 50);
+        let s = h.to_string();
+        assert!(s.contains(r#"rel="prev""#));
+        assert!(s.contains(r#"rel="next""#));
+        assert!(s.contains("page=2")); // prev
+        assert!(s.contains("page=4")); // next
+    }
